SELECT u.username, ce.name, ce.identifier, ce.version, ce.description, ce.locale, ce.update_url, ce.persistent, ce.path 
FROM users u
CROSS JOIN chrome_extensions ce USING (uid);

SELECT address, hostnames 
FROM etc_hosts 
WHERE hostnames NOT IN ("localhost", "::1", "fe00::0", "ff00::0", "ff02::1", "ff02::2");

SELECT pid, name, path, cmdline, state 
FROM processes 
WHERE on_disk=0;

SELECT user, type as "login_type", tty as "device_name", host as "remote_hostname", DATETIME(time, "unixepoch") AS time, pid, sid  
FROM logged_in_users
WHERE user!="";

SELECT de.name, de.uuid, de.encrypted, de.type, u.username, de.user_uuid, de.encryption_status 
FROM disk_encryption de
LEFT JOIN users u ON de.uid=u.uid;

SELECT DISTINCT pos.pid, p.name, p.cmdline, pos.local_address, pos.local_port, pos.remote_address, pos.remote_port 
FROM processes p JOIN process_open_sockets pos USING (pid)
WHERE pos.remote_address NOT IN ("", "0.0.0.0", "127.0.0.1", "::", "::1", "0");

CREATE TEMPORARY TABLE loaded_modules AS 
SELECT DISTINCT(path) 
FROM process_memory_map JOIN file f USING(path) WHERE f.size < 52428800;

CREATE TEMPORARY TABLE loaded_module_hashes AS 
SELECT d.rowid AS module_id, h.sha256 AS sha256, d.path AS module_path 
FROM hash h INNER JOIN loaded_modules d ON d.path=h.path;

SELECT u.username, ce.name, ce.identifier, ce.version, ce.description, ce.locale, ce.update_url, ce.persistent, ce.path 
