SELECT p.pid, p.name, p.path, lp.address, lp.protocol, lp.port
FROM listening_ports lp LEFT JOIN processes p ON lp.pid = p.pid
WHERE lp.port LIKE regex_match(lp.port, (SELECT v FROM __vars WHERE n = "port_pattern"), 0);

